import { createServer } from 'http'
import { parse as parseUrl } from 'url'
import { WebSocketServer } from 'ws'
import type { WebSocket as WsWebSocket } from 'ws'
import next from 'next'
import { Server as SocketIOServer } from 'socket.io'

const dev = process.env.NODE_ENV !== 'production'
const app = next({ dev })
const handle = app.getRequestHandler()

app.prepare().then(() => {
  const httpServer = createServer((req, res) => {
    const parsedUrl = parseUrl(req.url!, true)
    handle(req, res, parsedUrl)
  })

  // ─── Native WebSocket — WebRTC signaling ────────────────────────────────────
  const wss = new WebSocketServer({ noServer: true })

  // roomId -> Map<ws -> {username, peerId}>
  const rooms = new Map<string, Map<WsWebSocket, { username: string; peerId: string }>>()
  const wsPeerId = new Map<WsWebSocket, string>()
  const wsRoomInfo = new Map<WsWebSocket, { roomId: string; username: string; peerId: string }>()

  wss.on('connection', (ws: WsWebSocket, request) => {
    const url = new URL(request.url || '/', `http://${request.headers.host}`)
    const roomId = url.searchParams.get('room') || 'default'
    const username = decodeURIComponent(url.searchParams.get('name') || 'Anonymous')
    const peerId = 'p-' + Math.random().toString(36).slice(2, 10)

    // Register
    wsPeerId.set(ws, peerId)
    wsRoomInfo.set(ws, { roomId, username, peerId })

    if (!rooms.has(roomId)) rooms.set(roomId, new Map())
    rooms.get(roomId)!.set(ws, { username, peerId })

    // Send welcome to the new peer with list of existing peers
    const existingPeers = Array.from(rooms.get(roomId)!.entries())
      .filter(([w]) => w !== ws)
      .map(([, data]) => ({ peerId: data.peerId, username: data.username }))

    ws.send(JSON.stringify({
      type: 'welcome',
      peerId,
      peers: existingPeers,
      userCount: rooms.get(roomId)!.size,
    }))

    // Notify existing peers about the new peer
    broadcast(ws, {
      type: 'peer-joined',
      peerId,
      username,
    })

    ws.on('message', (raw) => {
      try {
        const msg = JSON.parse(raw.toString())
        handleMessage(ws, msg)
      } catch { /* ignore */ }
    })

    ws.on('close', () => {
      const info = wsRoomInfo.get(ws)
      if (info) {
        rooms.get(info.roomId)?.delete(ws)
        broadcast(ws, { type: 'peer-left', peerId: info.peerId })
        if (rooms.get(info.roomId)?.size === 0) {
          rooms.delete(info.roomId)
        }
      }
      wsPeerId.delete(ws)
      wsRoomInfo.delete(ws)
    })

    ws.on('error', () => ws.close())
  })

  function broadcast(sender: WsWebSocket, msg: object) {
    const info = wsRoomInfo.get(sender)
    if (!info) return
    const room = rooms.get(info.roomId)
    if (!room) return
    const payload = JSON.stringify(msg)
    room.forEach((_, ws) => {
      if (ws !== sender && ws.readyState === 1) {
        ws.send(payload)
      }
    })
  }

  function relay(targetPeerId: string, msg: object) {
    // Find the ws connection with this peerId
    const entries = Array.from(wsRoomInfo.entries())
    for (const [ws, info] of entries) {
      if (info.peerId === targetPeerId && ws.readyState === 1) {
        ws.send(JSON.stringify(msg))
        return
      }
    }
  }

  function handleMessage(ws: WsWebSocket, msg: any) {
    const info = wsRoomInfo.get(ws)
    if (!info) return
    const room = rooms.get(info.roomId)
    if (!room) return

    switch (msg.type) {
      case 'offer':
      case 'answer':
      case 'ice-candidate':
      case 'chat':
      case 'screen-share':
        // Relay to specific peer
        if (msg.peerId) {
          relay(msg.peerId, { ...msg, from: info.peerId, fromName: info.username })
        }
        break

      case 'join':
        // Already handled in 'connection' — ignore
        break
    }
  }

  // ─── Socket.IO — Pomodoro + ambient sounds ───────────────────────────────────
  const io = new SocketIOServer(httpServer, {
    cors: {
      origin: process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000',
      methods: ['GET', 'POST'],
    },
  })

  io.on('connection', (socket) => {
    socket.on('join-room', ({ roomId, username }: { roomId: string; username: string }) => {
      socket.join(roomId)
      const room = io.sockets.adapter.rooms.get(roomId)
      const count = room?.size ?? 0
      io.to(roomId).emit('user-joined', { username, id: socket.id, count })
      socket.data.username = username
      socket.data.roomId = roomId
    })

    socket.on('leave-room', ({ roomId, username }: { roomId: string; username: string }) => {
      socket.leave(roomId)
      const room = io.sockets.adapter.rooms.get(roomId)
      const count = room?.size ?? 0
      io.to(roomId).emit('user-left', { username, id: socket.id, count })
    })

    socket.on('pomodoro-tick', ({ roomId, timeLeft, phase, sessionCount }: any) => {
      socket.to(roomId).emit('pomodoro-sync', { timeLeft, phase, sessionCount })
    })

    socket.on('disconnect', () => {
      if (socket.data.roomId && socket.data.username) {
        const { roomId, username } = socket.data
        socket.leave(roomId)
        const room = io.sockets.adapter.rooms.get(roomId)
        const count = room?.size ?? 0
        io.to(roomId).emit('user-left', { username, id: socket.id, count })
      }
    })
  })

  // ─── HTTP upgrade ───────────────────────────────────────────────────────────
  httpServer.on('upgrade', (request, socket, head) => {
    const pathname = new URL(request.url || '/', `http://${request.headers.host}`).pathname
    if (pathname === '/') {
      wss.handleUpgrade(request, socket, head, (ws) => {
        wss.emit('connection', ws, request)
      })
    } else {
      socket.destroy()
    }
  })

  const port = Number(process.env.PORT) || 3000
  httpServer.listen(port, () => {
    console.log(`> Ready on http://localhost:${port}`)
  })
})
